import type { Metadata } from "next";
import Link from "next/link";

import "./globals.css";

export const metadata: Metadata = {
  title: "Minakeep",
  description: "Private notes and links, with selectively published public notes and links."
};

export default function RootLayout({ children }: Readonly<{ children: React.ReactNode }>) {
  return (
    <html lang="en">
      <body>
        <div className="page-shell">
          <header className="site-header">
            <div className="brand-block">
              <Link className="brand" href="/">
                Minakeep
              </Link>
              <p className="brand-caption">Private notes and saved references, with selectively public reading.</p>
            </div>
            <nav aria-label="Primary" className="site-nav">
              <Link href="/">Published notes</Link>
              <Link href="/login">Owner login</Link>
            </nav>
          </header>
          <main className="site-main">{children}</main>
        </div>
      </body>
    </html>
  );
}

import { PublicShowroom, type PublicShowroomItem } from "@/features/public-content/components/public-showroom";
import { listPublishedContent } from "@/features/public-content/service";

const publishedDateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });

export default async function HomePage() {
  const items = await listPublishedContent();
  const publishedLinks = items.filter((item) => item.kind === "link").length;
  const hasPublishedLinks = publishedLinks > 0;
  const showroomItems: PublicShowroomItem[] = items.map((item) => ({
    ...item,
    publishedAtLabel: publishedDateFormatter.format(item.publishedAt)
  }));

  return (
    <div className="feature-layout public-home-layout" data-testid="public-home-layout">
      <PublicShowroom defaultSearchExpanded={false} hasPublishedLinks={hasPublishedLinks} items={showroomItems} />
    </div>
  );
}

import Link from "next/link";
import type { ComponentPropsWithoutRef, ElementType, ReactNode } from "react";

function cx(...values: Array<string | false | null | undefined>) {
  return values.filter(Boolean).join(" ");
}

type SurfaceTone = "hero" | "panel" | "card" | "shell" | "inset";

const surfaceToneClasses: Record<SurfaceTone, string> = {
  hero: "hero-card ui-surface ui-surface-hero",
  panel: "panel-card ui-surface ui-surface-panel",
  card: "feature-card ui-surface ui-surface-card",
  shell: "vault-frame ui-surface ui-surface-shell",
  inset: "public-note-metadata ui-surface ui-surface-inset"
};

type SurfaceProps<T extends ElementType> = {
  as?: T;
  tone?: SurfaceTone;
  density?: "default" | "compact";
  children: ReactNode;
  className?: string;
} & Omit<ComponentPropsWithoutRef<T>, "as" | "children" | "className">;

export function Surface<T extends ElementType = "section">({
  as,
  tone = "panel",
  density = "default",
  children,
  className,
  ...props
}: SurfaceProps<T>) {
  const Component = as ?? "section";

  return (
    <Component className={cx(surfaceToneClasses[tone], density === "compact" && "ui-surface-compact", className)} {...props}>
      {children}
    </Component>
  );
}

type SectionHeadingProps = {
  title: ReactNode;
  meta?: ReactNode;
  className?: string;
};

export function SectionHeading({ title, meta, className }: SectionHeadingProps) {
  return (
    <div className={cx("section-heading ui-section-heading", className)}>
      <strong>{title}</strong>
      {meta ? <span className="section-meta">{meta}</span> : null}
    </div>
  );
}

type MetadataRowProps = ComponentPropsWithoutRef<"div"> & {
